mapper.select:
SELECT ,
       c.community_no, c.building_name, c.building_address, c.city
FROM frame f
LEFT JOIN community c ON f.community_id = c.id


        AND (
            f.frame_no LIKE CONCAT('%', #{keyword}, '%')
            OR f.building LIKE CONCAT('%', #{keyword}, '%')
            OR f.unit LIKE CONCAT('%', #{keyword}, '%')
            OR c.building_name LIKE CONCAT('%', #{keyword}, '%')
        )


        AND f.frame_no = #{frameNo}


        AND f.frame_no LIKE CONCAT('%', #{frameNoLike}, '%')


        AND f.community_id = #{communityId}


        AND f.community_id IN

            #{cid}



        AND f.building = #{building}


        AND f.building LIKE CONCAT('%', #{buildingLike}, '%')


        AND f.unit = #{unit}


        AND f.unit LIKE CONCAT('%', #{unitLike}, '%')


        AND f.elevator = #{elevator}


        AND f.elevator LIKE CONCAT('%', #{elevatorLike}, '%')


        AND f.inner_position = #{innerPosition}


        AND f.inner_position IN

            #{ip}



        AND c.city = #{city}


        AND c.building_name LIKE CONCAT('%', #{buildingNameLike}, '%')


ORDER BY f.id DESC

